/** Match backend _effective_payment_status — do not infer "paid" from amount alone. */
export function effectivePaymentStatus(inv) {
  const raw = (inv?.payment_status || "pending").toLowerCase();
  if (raw === "complete" || raw === "paid" || raw === "done") return "complete";
  const amount = parseFloat(inv?.amount) || 0;
  const paid = parseFloat(inv?.amount_paid) || 0;
  if (amount > 0 && paid > 0 && paid < amount) return "partial";
  if (raw === "partial") return "partial";
  return "pending";
}

export function paymentStatusLabel(status) {
  const s = (status || "pending").toLowerCase();
  if (s === "complete" || s === "paid") return "Paid";
  if (s === "partial") return "Partial";
  return "Unpaid";
}

export function paymentStatusStyle(status) {
  const s = (status || "pending").toLowerCase();
  if (s === "complete" || s === "paid") {
    return { bg: "var(--bg-warm, #F4EFE6)", color: "var(--brand-dark, #2F4A35)", border: "var(--border-default, #D4C8B8)" };
  }
  if (s === "partial") {
    return { bg: "#FAF0D1", color: "#6B5218", border: "#E5C387" };
  }
  return { bg: "#F8EBE7", color: "#8A3F27", border: "#E8A898" };
}

export function formatMoney(n) {
  if (n == null || Number.isNaN(Number(n))) return "—";
  return `${Number(n).toLocaleString("en-US", { maximumFractionDigits: 0 })} SAR`;
}
